from __future__ import annotations
from typing import Literal, TypeAlias

Role: TypeAlias = Literal["system", "user", "assistant"]
Message: TypeAlias = dict[str, str]

def make_message(role: Role, content: str) -> Message:
    return {"role": role, "content": content}

def build_conversation(
    system: str,
    turns: list[tuple[str, str]],  # list of (user_msg, assistant_msg) pairs
) -> list[Message]:
    messages: list[Message] = [make_message("system", system)]
    for user_text, assistant_text in turns:
        messages.append(make_message("user", user_text))
        messages.append(make_message("assistant", assistant_text))
    return messages

conv = build_conversation(
    system="You are a coding assistant.",
    turns=[
        ("How do I reverse a list in Python?", "Use `my_list[::-1]` or `list(reversed(my_list))`."),
        ("What about a string?", "Same slice syntax: `s[::-1]`."),
    ],
)
print(len(conv))  # 5: 1 system + 2 pairs

from __future__ import annotations
from typing import Any, Callable, Literal, TypeAlias
import anthropic

# Types
Role: TypeAlias = Literal["user", "assistant"]
ToolFn: TypeAlias = Callable[..., dict[str, Any]]
Message: TypeAlias = dict[str, Any]

class ToolRegistry:
    def __init__(self) -> None:
        self._tools: dict[str, ToolFn] = {}

    def register(self, name: str, fn: ToolFn) -> None:
        self._tools[name] = fn

    def call(self, name: str, **kwargs: Any) -> dict[str, Any]:
        if name not in self._tools:
            raise KeyError(f"Unknown tool: {name}")
        return self._tools[name](**kwargs)

    def names(self) -> list[str]:
        return list(self._tools.keys())

# Register tools
registry = ToolRegistry()

def web_search(query: str, max_results: int = 5) -> dict[str, Any]:
    return {"results": [f"Result {i}: {query}" for i in range(max_results)]}

registry.register("web_search", web_search)

# Type-safe agent loop
client = anthropic.Anthropic()

def run_agent(user_message: str, max_turns: int = 5) -> str:
    messages: list[Message] = [{"role": "user", "content": user_message}]

    for _ in range(max_turns):
        response = client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=1024,
            messages=messages,
        )
        # response.stop_reason: str | None
        if response.stop_reason == "end_turn":
            text: str = response.content[0].text  # type: ignore[union-attr]
            return text
        messages.append({"role": "assistant", "content": response.content})

    return "Max turns reached"

print(run_agent("What is the capital of France?"))
